/**
 *  * NorthWest Digital – script.js
  * Features:
   *  1. Sticky navbar with scroll detection + logo color swap
    *  2. Hamburger menu toggle (mobile)
     *  3. Smooth scrolling for nav links (with offset for fixed nav)
      *  4. Scroll-triggered fade-in animations (IntersectionObserver)
       *  5. Lightbox for portfolio images
        *  6. Contact form client-side validation
         *  7. Back-to-top button
          *  8. Footer year auto-update
           */

           // ──────────────────────────────────────────────────────────────────
           // Utility: safely select single element
           // ──────────────────────────────────────────────────────────────────
           const $ = (selector, parent = document) => parent.querySelector(selector);
           const $$ = (selector, parent = document) => [...parent.querySelectorAll(selector)];

           // ──────────────────────────────────────────────────────────────────
           // 1. STICKY NAVBAR
           // Adds .scrolled class when user scrolls past the hero viewport
           // ──────────────────────────────────────────────────────────────────
           (function initNavbar() {
             const navbar = $('#navbar');
               if (!navbar) return;

                 function onScroll() {
                     if (window.scrollY > 60) {
                           navbar.classList.add('scrolled');
                               } else {
                                     navbar.classList.remove('scrolled');
                                         }
                                           }

                                             window.addEventListener('scroll', onScroll, { passive: true });
                                               onScroll(); // run on load in case user refreshes mid-page
                                               })();
                                               // ──────────────────────────────────────────────────────────────────
                                               // 2. HAMBURGER MENU TOGGLE
                                               // ──────────────────────────────────────────────────────────────────
                                               (function initHamburger() {
                                                 const hamburger = $('#hamburger');
                                                   const navLinks  = $('#navLinks');
                                                     if (!hamburger || !navLinks) return;

                                                       function closeMenu() {
                                                           hamburger.classList.remove('active');
                                                               navLinks.classList.remove('open');
                                                                   hamburger.setAttribute('aria-expanded', 'false');
                                                                     }

                                                                       function openMenu() {i
                                                                           hamburger.classList.add('active');
                                                                               navLinks.classList.add('open');
                                                                                   hamburger.setAttribute('aria-expanded', 'true');
                                                                                     }

                                                                                       hamburger.addEventListener('click', () => {
                                                                                           const isOpen = navLinks.classList.contains('open');
                                                                                               isOpen ? closeMenu() : openMenu();
                                                                                                 });

                                                                                                   // Close menu when a nav link is clicked
                                                                                                     $$('.nav-link', navLinks).forEach(link => {
                                                                                                         link.addEventListener('click', closeMenu);
                                                                                                           });

                                                                                                             // Close menu when clicking outside the nav
                                                                                                               document.addEventListener('click', (e) => {
                                                                                                                   if (!navbar.contains(e.target) && navLinks.classList.contains('open')) {
                                                                                                                         closeMenu();
                                                                                                                             }
                                                                                                                               });

                                                                                                                                 // Close menu on Escape key
                                                                                                                                   document.addEventListener('keydown', (e) => {
                                                                                                                                       if (e.key === 'Escape' && navLinks.classList.contains('open')) {
                                                                                                                                             closeMenu();
                                                                                                                                                   hamburger.focus();
                                                                                                                                                       }
                                                                                                                                                         });
                                                                                                                                                         })();
                                                                                                                                                         // ──────────────────────────────────────────────────────────────────
                                                                                                                                                         // 3. SMOOTH SCROLLING WITH NAV OFFSET
                                                                                                                                                         // Intercepts all anchor links pointing to #sections
                                                                                                                                                         // ──────────────────────────────────────────────────────────────────
                                                                                                                                                         (function initSmoothScroll() {
                                                                                                                                                           const navHeight = parseInt(
                                                                                                                                                               getComputedStyle(document.documentElement).getPropertyValue('--nav-height') || '72',
                                                                                                                                                                   10
                                                                                                                                                                     );

                                                                                                                                                                       document.addEventListener('click', (e) => {
                                                                                                                                                                           const link = e.target.closest('a[href^="#"]');
                                                                                                                                                                               if (!link) return;

                                                                                                                                                                                   const targetId = link.getAttribute('href');
                                                                                                                                                                                       if (targetId === '#') return;

                                                                                                                                                                                           const target = document.querySelector(targetId);
                                                                                                                                                                                               if (!target) return;

                                                                                                                                                                                                   e.preventDefault();

                                                                                                                                                                                                       const targetTop = target.getBoundingClientRect().top + window.scrollY - navHeight - 8;

                                                                                                                                                                                                           window.scrollTo({ top: targetTop, behavior: 'smooth' });
                                                                                                                                                                                                             });
                                                                                                                                                                                                             })();

                                                                                                                                                                                                             // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                             // 4. SCROLL-TRIGGERED FADE-IN ANIMATIONS
                                                                                                                                                                                                             // Uses IntersectionObserver to add .visible to .reveal elements
                                                                                                                                                                                                             // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                             (function initScrollReveal() {
                                                                                                                                                                                                               const elements = $$('.reveal');
                                                                                                                                                                                                                 if (!elements.length) return;

                                                                                                                                                                                                                   // Use requestAnimationFrame for performance
                                                                                                                                                                                                                     const observer = new IntersectionObserver(
                                                                                                                                                                                                                         (entries) => {
                                                                                                                                                                                                                               entries.forEach(entry => {
                                                                                                                                                                                                                                       if (entry.isIntersecting) {
                                                                                                                                                                                                                                                 // Use rAF to batch DOM writes
                                                                                                                                                                                                                                                           requestAnimationFrame(() => {
                                                                                                                                                                                                                                                                       entry.target.classList.add('visible');
                                                                                                                                                                                                                                                                                 });
                                                                                                                                                                                                                                                                                           observer.unobserve(entry.target); // only animate once
                                                                                                                                                                                                                                                                                                   }
                                                                                                                                                                                                                                                                                                         });
                                                                                                                                                                                                                                                                                                             },
                                                                                                                                                                                                                                                                                                                 {
                                                                                                                                                                                                                                                                                                                       threshold: 0.12,       // trigger when 12% of element is visible
                                                                                                                                                                                                                                                                                                                             rootMargin: '0px 0px -40px 0px' // slightly before viewport edge
                                                                                                                                                                                                                                                                                                                                 }
                                                                                                                                                                                                                                                                                                                                   );

                                                                                                                                                                                                                                                                                                                                     elements.forEach(el => observer.observe(el));
                                                                                                                                                                                                                                                                                                                                     })();


                                                                                                                                                                                                                                                                                                                                     // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                     // 5. LIGHTBOX
                                                                                                                                                                                                                                                                                                                                     // Opens when user clicks a .portfolio-thumb-btn
                                                                                                                                                                                                                                                                                                                                     // Reads data-img, data-title, data-desc attributes
                                                                                                                                                                                                                                                                                                                                     // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                     (function initLightbox() {
                                                                                                                                                                                                                                                                                                                                       const lightbox      = $('#lightbox');
                                                                                                                                                                                                                                                                                                                                         const closeBtn      = $('#lightboxClose');
                                                                                                                                                                                                                                                                                                                                           const lightboxImg   = $('#lightboxImg');
                                                                                                                                                                                                                                                                                                                                             const lightboxTitle = $('#lightboxTitle');
                                                                                                                                                                                                                                                                                                                                               const lightboxDesc  = $('#lightboxDesc');

                                                                                                                                                                                                                                                                                                                                                 if (!lightbox) return;

                                                                                                                                                                                                                                                                                                                                                   // Open lightbox
                                                                                                                                                                                                                                                                                                                                                     function openLightbox(imgSrc, title, desc, altText) {
                                                                                                                                                                                                                                                                                                                                                         lightboxImg.src   = imgSrc;
                                                                                                                                                                                                                                                                                                                                                             lightboxImg.alt   = altText || title;
                                                                                                                                                                                                                                                                                                                                                                 lightboxTitle.textContent = title;
                                                                                                                                                                                                                                                                                                                                                                     lightboxDesc.textContent  = desc;
                                                                                                                                                                                                                                                                                                                                                                         lightbox.hidden = false;
                                                                                                                                                                                                                                                                                                                                                                             document.body.style.overflow = 'hidden'; // prevent background scroll
                                                                                                                                                                                                                                                                                                                                                                                 closeBtn.focus();
                                                                                                                                                                                                                                                                                                                                                                                   }
                                                                                                                                                                                                                                                                                                                                                                                   // Close lightbox
                                                                                                                                                                                                                                                                                                                                                                                     function closeLightbox() {
                                                                                                                                                                                                                                                                                                                                                                                         lightbox.hidden = true;
                                                                                                                                                                                                                                                                                                                                                                                             lightboxImg.src = '';
                                                                                                                                                                                                                                                                                                                                                                                                 document.body.style.overflow = '';
                                                                                                                                                                                                                                                                                                                                                                                                   }

                                                                                                                                                                                                                                                                                                                                                                                                     // Trigger: portfolio thumbnails
                                                                                                                                                                                                                                                                                                                                                                                                       $$('.portfolio-thumb-btn').forEach(btn => {
                                                                                                                                                                                                                                                                                                                                                                                                           btn.addEventListener('click', () => {
                                                                                                                                                                                                                                                                                                                                                                                                                 const imgSrc = btn.dataset.img   || '';
                                                                                                                                                                                                                                                                                                                                                                                                                       const title  = btn.dataset.title || '';
                                                                                                                                                                                                                                                                                                                                                                                                                             const desc   = btn.dataset.desc  || '';
                                                                                                                                                                                                                                                                                                                                                                                                                                   const alt    = btn.querySelector('img')?.alt || title;
                                                                                                                                                                                                                                                                                                                                                                                                                                         openLightbox(imgSrc, title, desc, alt);
                                                                                                                                                                                                                                                                                                                                                                                                                                             });
                                                                                                                                                                                                                                                                                                                                                                                                                                               });

                                                                                                                                                                                                                                                                                                                                                                                                                                                 // Close: close button
                                                                                                                                                                                                                                                                                                                                                                                                                                                   closeBtn.addEventListener('click', closeLightbox);

                                                                                                                                                                                                                                                                                                                                                                                                                                                     // Close: click backdrop (outside inner content)
                                                                                                                                                                                                                                                                                                                                                                                                                                                       lightbox.addEventListener('click', (e) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                           if (e.target === lightbox) closeLightbox();
                                                                                                                                                                                                                                                                                                                                                                                                                                                             });

                                                                                                                                                                                                                                                                                                                                                                                                                                                               // Close: Escape key
                                                                                                                                                                                                                                                                                                                                                                                                                                                                 document.addEventListener('keydown', (e) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                     if (e.key === 'Escape' && !lightbox.hidden) closeLightbox();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                       });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                       })();


                                                                                                                                                                                                                                                                                                                                                                                                                                                                       // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                       // 6. CONTACT FORM VALIDATION
                                                                                                                                                                                                                                                                                                                                                                                                                                                                       // Client-side only; shows inline errors and a success message
                                                                                                                                                                                                                                                                                                                                                                                                                                                                       // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                       (function initContactForm() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                         const form       = $('#contactForm');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                           const submitBtn  = $('#submitBtn');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                             const feedback   = $('#formFeedback');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                               if (!form) return;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 // Validator rules
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   const validators = {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       name: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             validate: (v) => v.trim().length >= 2,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   message:  'Please enter your full name (at least 2 characters).'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           email: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 validate: (v) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v.trim()),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       message:  'Please enter a valid email address.'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               message: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     validate: (v) => v.trim().length >= 10,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           message:  'Please write a message (at least 10 characters).'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 // Show error for a specific field
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   function showError(fieldId, message) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       const input = $('#' + fieldId, form);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           const errorEl = $('#' + fieldId + '-error', form);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               if (input) input.classList.add('error');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   if (errorEl) errorEl.textContent = message;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       // Clear error for a specific field
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         function clearError(fieldId) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             const input = $('#' + fieldId, form);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 const errorEl = $('#' + fieldId + '-error', form);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     if (input) input.classList.remove('error');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         if (errorEl) errorEl.textContent = '';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             // Live validation: clear error as user types
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               Object.keys(validators).forEach(fieldId => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   const input = $('#' + fieldId, form);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       if (!input) return;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           input.addEventListener('input', () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 if (validators[fieldId].validate(input.value)) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         clearError(fieldId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       // Validate on blur too
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           input.addEventListener('blur', () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 if (!validators[fieldId].validate(input.value)) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         showError(fieldId, validators[fieldId].message);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       clearError(fieldId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     // Form submission
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       form.addEventListener('submit', async (e) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           e.preventDefault();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               // Clear previous feedback
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   feedback.hidden = true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       feedback.className = 'form-feedback';

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           // Validate all fields
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               let isValid = true;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   Object.keys(validators).forEach(fieldId => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         const input = $('#' + fieldId, form);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               clearError(fieldId);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     if (input && !validators[fieldId].validate(input.value)) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             showError(fieldId, validators[fieldId].message);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     isValid = false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   if (!isValid) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         // Focus first invalid field
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               const firstError = form.querySelector('.form-input.error');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     if (firstError) firstError.focus();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           return;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 // Simulate form submission (no backend)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     submitBtn.classList.add('loading');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         const btnText = submitBtn.querySelector('.btn-text');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             const originalText = btnText.textContent;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 btnText.textContent = 'Sending…';

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     // Simulate async delay (1.5s)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         await new Promise(resolve => setTimeout(resolve, 1500));

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             // Show success message
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 submitBtn.classList.remove('loading');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     btnText.textContent = originalText;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         feedback.textContent = "✅ Thank you! Your message has been received. Well will get back to you within 24 hours.";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         hv
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             feedback.classList.add('success');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 feedback.hidden = false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     feedback.scrollIntoView({ behavior: 'smooth', block: 'nearest' });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         // Reset form fields (but keep it visible)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             form.reset();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 // Hide feedback after 8 seconds
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     setTimeout(() => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           feedback.hidden = true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               }, 8000);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 })();

 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 // 7. BACK-TO-TOP BUTTON
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 (function initBackToTop() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   const btn = $('#backToTop');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     if (!btn) return;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       window.addEventListener('scroll', () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           if (window.scrollY > 500) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 btn.hidden = false;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           btn.hidden = true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 }, { passive: true });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   btn.addEventListener('click', () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       window.scrollTo({ top: 0, behavior: 'smooth' });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         })();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         // 8. FOOTER YEAR AUTO-UPDATE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         (function setFooterYear() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           const yearEl = $('#year');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             if (yearEl) yearEl.textContent = new Date().getFullYear();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             })();


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             // 9. ACTIVE NAV LINK HIGHLIGHT ON SCROLL
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             // Highlights which section the user is currently viewing
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             // ──────────────────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             (function initActiveNavHighlight() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               const sections  = $$('section[id]');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 const navLinks  = $$('.nav-link');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   const navHeight = 80;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     function onScroll() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         let current = '';

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             sections.forEach(section => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   const sectionTop = section.offsetTop - navHeight - 40;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         if (window.scrollY >= sectionTop) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 current = section.getAttribute('id');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               navLinks.forEach(link => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     link.classList.remove('active');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           if (link.getAttribute('href') === '#' + current) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   link.classList.add('active');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 window.addEventListener('scroll', onScroll, { passive: true });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 })();